                  fun ?maxPasswordAge ->
                    fun ?passwordReusePrevention ->
                      fun ?hardExpiry ->
                        fun () ->
                          {
                            minimumPasswordLength;
                            requireSymbols;
                            requireNumbers;
                            requireUppercaseCharacters;
                            requireLowercaseCharacters;
                            allowUsersToChangePassword;
                            expirePasswords;
                            maxPasswordAge;
                            passwordReusePrevention;
                            hardExpiry
